import { createClient } from "@liveblocks/client";
import { createRoomContext } from "@liveblocks/react";

const client = createClient({
  publicApiKey: process.env.NEXT_PUBLIC_LIVEBLOCKS_PUBLIC_KEY!,
});

export const {
  suspense: {
    RoomProvider,
    useRoom,
    useSelf,
    useOthers,
  },
} = createRoomContext(client);

export { client };

import { Liveblocks } from "@liveblocks/node";
import { NextRequest, NextResponse } from "next/server";

const liveblocks = new Liveblocks({
  secret: process.env.LIVEBLOCKS_SECRET_KEY!,
});

// A small palette of user colors for cursor display
const USER_COLORS = [
  "#E57373", "#F06292", "#BA68C8", "#7986CB",
  "#64B5F6", "#4DB6AC", "#81C784", "#FFD54F",
  "#FF8A65", "#A1887F",
];

// Simple adjective + noun combos for random guest names
const ADJECTIVES = ["Swift", "Bright", "Cool", "Bold", "Calm", "Keen", "Wise", "Fair"];
const NOUNS = ["Otter", "Eagle", "Tiger", "Panda", "Raven", "Lynx", "Finch", "Crane"];

function randomElement<T>(arr: T[]): T {
  return arr[Math.floor(Math.random() * arr.length)];
}

export async function POST(request: NextRequest) {
  // Prepare a random guest identity for this session
  const name = `${randomElement(ADJECTIVES)} ${randomElement(NOUNS)}`;
  const color = USER_COLORS[Math.floor(Math.random() * USER_COLORS.length)];

  const { status, body } = await liveblocks.identifyUser(
    {
      userId: `user-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
      groupIds: [],
    },
    {
      userInfo: {
        name,
        color,
      },
    }
  );

  return new NextResponse(body, { status });
}

import { NextRequest, NextResponse } from "next/server";

// In-memory snapshot store: roomId → blocks array
const snapshots = new Map<string, unknown[]>();

export async function POST(request: NextRequest) {
  let body: { roomId?: string; blocks?: unknown[] };

  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON" }, { status: 400 });
  }

  const { roomId, blocks } = body;

  if (!roomId || typeof roomId !== "string") {
    return NextResponse.json({ error: "roomId is required" }, { status: 400 });
  }
  if (!Array.isArray(blocks)) {
    return NextResponse.json({ error: "blocks must be an array" }, { status: 400 });
  }

  snapshots.set(roomId, blocks);

  return NextResponse.json(
    { ok: true, roomId, blockCount: blocks.length },
    { status: 200 }
  );
}

export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url);
  const roomId = searchParams.get("roomId");

  if (!roomId) {
    return NextResponse.json({ error: "roomId query param is required" }, { status: 400 });
  }

  const blocks = snapshots.get(roomId);
  if (blocks === undefined) {
    return NextResponse.json({ error: "not_found" }, { status: 404 });
  }

  return NextResponse.json({ roomId, blocks }, { status: 200 });
}

