"use client";

import { Suspense, useMemo } from "react";
import { useSearchParams } from "next/navigation";
import {
  LiveblocksProvider,
  RoomProvider,
  useRoom,
} from "@liveblocks/react";
import { getYjsProviderForRoom } from "@liveblocks/yjs";
import { useCreateBlockNote } from "@blocknote/react";
import { BlockNoteView } from "@blocknote/mantine";
import "@blocknote/mantine/style.css";
import "@blocknote/core/fonts/inter.css";

// The run-id is used to namespace the default room so each test run is isolated.
const RUN_ID = process.env.NEXT_PUBLIC_ZEALT_RUN_ID ?? "";
const DEFAULT_ROOM = RUN_ID ? `blocknote-default-${RUN_ID}` : "blocknote-default";

// ─── Inner editor: lives inside RoomProvider ──────────────────────────────────
function CollaborativeEditor({ roomId }: { roomId: string }) {
  const room = useRoom();

  // Get (or create) the Liveblocks Yjs provider for this room.
  // getYjsProviderForRoom is idempotent – same instance is returned on every render.
  const provider = useMemo(() => getYjsProviderForRoom(room), [room]);

  // Derive the shared Y.Doc and the XML fragment BlockNote expects.
  const ydoc = provider.getYDoc();
  const fragment = ydoc.getXmlFragment("document-store");

  // Generate stable per-session user info.
  const userInfo = useMemo(() => {
    const COLORS = [
      "#E57373", "#F06292", "#BA68C8", "#7986CB",
      "#64B5F6", "#4DB6AC", "#81C784", "#FFD54F",
    ];
    const NAMES = [
      "Alice", "Bob", "Carol", "Dave",
      "Eve", "Frank", "Grace", "Heidi",
    ];
    return {
      name: NAMES[Math.floor(Math.random() * NAMES.length)],
      color: COLORS[Math.floor(Math.random() * COLORS.length)],
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // intentionally empty – stable across renders for this session

  const editor = useCreateBlockNote({
    collaboration: {
      provider,
      fragment,
      user: {
        name: userInfo.name,
        color: userInfo.color,
      },
    },
  });

  async function handleSave() {
    try {
      const res = await fetch("/api/snapshots", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ roomId, blocks: editor.document }),
      });
      if (res.ok) {
        alert("Snapshot saved!");
      } else {
        alert("Failed to save snapshot.");
      }
    } catch (err) {
      alert(`Error saving snapshot: ${err}`);
    }
  }

  return (
    <div>
      <div style={{ marginBottom: 8, display: "flex", gap: 8, alignItems: "center" }}>
        <span style={{ fontWeight: 600 }}>Room:</span>
        <code style={{ background: "#f3f4f6", padding: "2px 8px", borderRadius: 4 }}>
          {roomId}
        </code>
        <button
          onClick={handleSave}
          style={{
            marginLeft: "auto",
            padding: "6px 16px",
            background: "#4F46E5",
            color: "#fff",
            border: "none",
            borderRadius: 6,
            cursor: "pointer",
            fontWeight: 600,
          }}
        >
          Save snapshot
        </button>
      </div>
      <BlockNoteView editor={editor} />
    </div>
  );
}

// ─── Root room wrapper: reads ?room= from the URL ─────────────────────────────
function EditorRoot() {
  const searchParams = useSearchParams();
  const roomId = searchParams.get("room") ?? DEFAULT_ROOM;

  return (
    <LiveblocksProvider
      publicApiKey={process.env.NEXT_PUBLIC_LIVEBLOCKS_PUBLIC_KEY!}
    >
      <RoomProvider id={roomId} initialPresence={{}}>
        <CollaborativeEditor roomId={roomId} />
      </RoomProvider>
    </LiveblocksProvider>
  );
}

// ─── Page export ──────────────────────────────────────────────────────────────
export default function EditorPage() {
  return (
    <main style={{ padding: 16, maxWidth: 900, margin: "0 auto" }}>
      <h2 style={{ marginBottom: 12 }}>BlockNote × Liveblocks Yjs</h2>
      <Suspense fallback={<p>Loading editor…</p>}>
        <EditorRoot />
      </Suspense>
    </main>
  );
}

