// Shim that re-exports everything from prosemirror-view and adds
// the __serializeForClipboard export that @blocknote/core needs.
export * from "prosemirror-view";

// The underlying serializeForClipboard function was made private in
// prosemirror-view >=1.34; we reconstruct a compatible shim using the
// publicly-accessible DOMSerializer so BlockNote can still copy/paste.
import { EditorView } from "prosemirror-view";
import { DOMSerializer } from "prosemirror-model";

export function __serializeForClipboard(view, slice) {
  const schema = view.state.schema;
  const serializer =
    view.someProp("clipboardSerializer") || DOMSerializer.fromSchema(schema);
  const doc = document.createElement("div");
  const dom = serializer.serializeFragment(slice.content, { document }, doc);
  let nodes = dom.childNodes;
  let text = "";
  nodes.forEach((node) => {
    if (node.textContent) text += node.textContent + "\n";
  });
  return { dom, text };
}

